52	/// Generate a line-level diff between old and new docket text.
53	///
54	/// Uses longest-common-subsequence to produce unified-style output:
55	/// unchanged lines shown as-is, removed lines prefixed with "- ",
56	/// added lines prefixed with "+ ".
57	fn jjrtl_diff_docket(old: &str, new: &str) -> String {
58	    let old_lines: Vec<&str> = old.lines().collect();
59	    let new_lines: Vec<&str> = new.lines().collect();
60	    let m = old_lines.len();
61	    let n = new_lines.len();
62	
63	    // Build LCS table
64	    let mut dp = vec![vec![0u32; n + 1]; m + 1];
65	    for i in (0..m).rev() {
66	        for j in (0..n).rev() {
67	            dp[i][j] = if old_lines[i] == new_lines[j] {
68	                dp[i + 1][j + 1] + 1
69	            } else {
70	                dp[i + 1][j].max(dp[i][j + 1])
71	            };
72	        }
73	    }
74	
75	    // Walk the table to emit diff lines
76	    let mut result = String::new();
77	    let mut i = 0;
78	    let mut j = 0;
79	    while i < m || j < n {
80	        if i < m && j < n && old_lines[i] == new_lines[j] {
81	            // Context line — skip to keep output compact
82	            i += 1;
83	            j += 1;
84	        } else if i < m && (j >= n || dp[i + 1][j] >= dp[i][j + 1]) {
85	            result.push_str("- ");
86	            result.push_str(old_lines[i]);
87	            result.push('\n');
88	            i += 1;
89	        } else {
90	            result.push_str("+ ");
91	            result.push_str(new_lines[j]);
92	            result.push('\n');
93	            j += 1;
94	        }
95	    }
96	
97	    result
98	}
