5	//! Gazette — two-level map with freeze-on-disclosure semantics
6	//!
7	//! Implements the JJSCGZ-gazette.adoc specification.
8	//! A gazette maps (slug, lede) pairs to content strings,
9	//! with a fixed vocabulary of accepted slugs and permanent
10	//! freeze-on-disclosure semantics.
11	
12	use std::cell::Cell;
13	use std::collections::BTreeMap;
14	use std::fmt;
15	
16	// --- String boundary consts for slug wire format ---
17	
18	pub(crate) const JJRZ_SLUG_SLATE: &str = "jjezs_slate";
19	pub(crate) const JJRZ_SLUG_RESLATE: &str = "jjezs_reslate";
20	pub(crate) const JJRZ_SLUG_PADDOCK: &str = "jjezs_paddock";
21	pub(crate) const JJRZ_SLUG_PACE: &str = "jjezs_pace";
22	
23	/// Slug direction — metadata for how each slug is used in operations
24	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
25	pub enum jjrz_Direction {
26	    Input,
27	    Output,
28	    Bidirectional,
29	}
30	
31	/// Slug enumeration — category identifiers for gazette notices
32	#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
33	pub enum jjrz_Slug {
34	    Slate,
35	    Reslate,
36	    Paddock,
37	    Pace,
38	}
39	
40	/// All defined slug values
41	pub const JJRZ_ALL_SLUGS: &[jjrz_Slug] = &[
42	    jjrz_Slug::Slate,
43	    jjrz_Slug::Reslate,
44	    jjrz_Slug::Paddock,
45	    jjrz_Slug::Pace,
46	];
47	
48	impl jjrz_Slug {
49	    /// Wire-format string for this slug
50	    pub fn jjrz_as_str(&self) -> &'static str {
51	        match self {
52	            Self::Slate => JJRZ_SLUG_SLATE,
53	            Self::Reslate => JJRZ_SLUG_RESLATE,
54	            Self::Paddock => JJRZ_SLUG_PADDOCK,
55	            Self::Pace => JJRZ_SLUG_PACE,
56	        }
57	    }
58	
59	    /// Parse slug from wire-format string (exact match only)
60	    pub fn jjrz_from_str(s: &str) -> Option<jjrz_Slug> {
61	        match s {
62	            JJRZ_SLUG_SLATE => Some(Self::Slate),
63	            JJRZ_SLUG_RESLATE => Some(Self::Reslate),
64	            JJRZ_SLUG_PADDOCK => Some(Self::Paddock),
65	            JJRZ_SLUG_PACE => Some(Self::Pace),
66	            _ => None,
67	        }
68	    }
69	
70	    /// Direction metadata per spec
71	    pub fn jjrz_direction(&self) -> jjrz_Direction {
72	        match self {
73	            Self::Slate => jjrz_Direction::Input,
74	            Self::Reslate => jjrz_Direction::Input,
75	            Self::Paddock => jjrz_Direction::Bidirectional,
76	            Self::Pace => jjrz_Direction::Output,
77	        }
78	    }
79	}
80	
81	impl fmt::Display for jjrz_Slug {
82	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
83	        f.write_str(self.jjrz_as_str())
84	    }
85	}
86	
87	/// Two-level map gazette with freeze-on-disclosure semantics
88	#[derive(Debug)]
89	pub struct jjrz_Gazette {
90	    vocabulary: Vec<jjrz_Slug>,
91	    notices: BTreeMap<jjrz_Slug, BTreeMap<String, String>>,
92	    frozen: Cell<bool>,
93	}
94	
95	impl jjrz_Gazette {
96	    /// Construct a frozen gazette from raw markdown per the wire format.
97	    ///
98	    /// All validation errors are collected and returned as a diagnostic list
99	    /// rather than failing on the first.
100	    pub fn jjrz_parse(vocabulary: &[jjrz_Slug], markdown: &str) -> Result<jjrz_Gazette, Vec<String>> {
101	        let mut diagnostics: Vec<String> = Vec::new();
102	        let mut notices: BTreeMap<jjrz_Slug, BTreeMap<String, String>> = BTreeMap::new();
103	        let vocab_set: std::collections::HashSet<jjrz_Slug> = vocabulary.iter().copied().collect();
104	
105	        // (slug, lede, content_lines, header_line_number)
106	        let mut current: Option<(jjrz_Slug, String, Vec<String>, usize)> = None;
107	        let mut in_fence = false;
108	
109	        for (line_idx, line) in markdown.lines().enumerate() {
110	            let line_num = line_idx + 1;
111	
112	            if line.starts_with("```") {
113	                in_fence = !in_fence;
114	            }
115	
116	            if !in_fence && zjjrz_is_notice_boundary(line) {
117	                if let Some((slug, lede, content_lines, hdr_line)) = current.take() {
118	                    zjjrz_finalize_notice(slug, &lede, &content_lines, hdr_line, &mut notices, &mut diagnostics);
119	                }
120	
121	                let after_hash = line[1..].trim();
122	                if after_hash.is_empty() {
123	                    diagnostics.push(format!("Line {}: malformed header (no slug after #)", line_num));
124	                    continue;
125	                }
126	
127	                let (slug_str, lede) = match after_hash.split_once(char::is_whitespace) {
128	                    Some((s, l)) => (s, l.trim().to_string()),
129	                    None => (after_hash, String::new()),
130	                };
131	
132	                match jjrz_Slug::jjrz_from_str(slug_str) {
133	                    Some(slug) if vocab_set.contains(&slug) => {
134	                        current = Some((slug, lede, Vec::new(), line_num));
135	                    }
136	                    Some(slug) => {
137	                        diagnostics.push(format!(
138	                            "Line {}: slug '{}' not in vocabulary (accepted: {})",
139	                            line_num, slug, zjjrz_format_vocab(vocabulary)
140	                        ));
141	                    }
142	                    None => {
143	                        diagnostics.push(format!(
144	                            "Line {}: unknown slug '{}' (valid: {})",
145	                            line_num, slug_str, zjjrz_format_vocab(vocabulary)
146	                        ));
147	                    }
148	                }
149	            } else if let Some((_, _, ref mut content_lines, _)) = current {
150	                content_lines.push(line.to_string());
151	            }
152	        }
153	
154	        if let Some((slug, lede, content_lines, hdr_line)) = current.take() {
155	            zjjrz_finalize_notice(slug, &lede, &content_lines, hdr_line, &mut notices, &mut diagnostics);
156	        }
157	
158	        if diagnostics.is_empty() {
159	            Ok(jjrz_Gazette {
160	                vocabulary: vocabulary.to_vec(),
161	                notices,
162	                frozen: Cell::new(true),
163	            })
164	        } else {
165	            Err(diagnostics)
166	        }
167	    }
168	
169	    /// Construct an unfrozen, empty gazette
170	    pub fn jjrz_build(vocabulary: &[jjrz_Slug]) -> jjrz_Gazette {
171	        jjrz_Gazette {
172	            vocabulary: vocabulary.to_vec(),
173	            notices: BTreeMap::new(),
174	            frozen: Cell::new(false),
175	        }
176	    }
177	
178	    /// Add a notice to the gazette.
179	    ///
180	    /// Fatal if frozen, if slug is not in vocabulary, or if (slug, lede) already exists.
181	    pub fn jjrz_add(&mut self, slug: jjrz_Slug, lede: &str, content: &str) -> Result<(), String> {
182	        if self.frozen.get() {
183	            return Err("Cannot add to frozen gazette".to_string());
184	        }
185	        if !self.vocabulary.contains(&slug) {
186	            return Err(format!(
187	                "Slug '{}' not in vocabulary (accepted: {})",
188	                slug, zjjrz_format_vocab(&self.vocabulary)
189	            ));
190	        }
191	        let inner = self.notices.entry(slug).or_default();
192	        if inner.contains_key(lede) {
193	            let lede_display = if lede.is_empty() { "<absent>" } else { lede };
194	            return Err(format!("Duplicate key ({}, {:?})", slug, lede_display));
195	        }
196	        inner.insert(lede.to_string(), content.to_string());
197	        Ok(())
198	    }
199	
200	    /// Retrieve all notices with the given slug.
201	    /// Discloses notice map contents (freezes gazette permanently).
202	    pub fn jjrz_query_by_slug(&self, slug: jjrz_Slug) -> Vec<(String, String)> {
203	        self.frozen.set(true);
204	        self.notices.get(&slug)
205	            .map(|inner| inner.iter().map(|(l, c)| (l.clone(), c.clone())).collect())
206	            .unwrap_or_default()
207	    }
208	
209	    /// Retrieve all notices.
210	    /// Discloses notice map contents (freezes gazette permanently).
211	    pub fn jjrz_query_all(&self) -> Vec<(jjrz_Slug, String, String)> {
212	        self.frozen.set(true);
213	        let mut result = Vec::new();
214	        for (&slug, inner) in &self.notices {
215	            for (lede, content) in inner {
216	                result.push((slug, lede.clone(), content.clone()));
217	            }
218	        }
219	        result
220	    }
221	
222	    /// Produce formatted markdown per the wire format.
223	    /// Discloses notice map contents (freezes gazette permanently).
224	    pub fn jjrz_emit(&self) -> String {
225	        self.frozen.set(true);
226	        let mut output = String::new();
227	        let mut first = true;
228	        for (&slug, inner) in &self.notices {
229	            for (lede, content) in inner {
230	                if !first {
