282	/// Parse gazette input for revise_docket (reslate) operation.
283	/// Returns Vec of (coronet, docket) pairs for mass reslate support.
284	/// Validates: at least one reslate notice, all ledes (coronets) non-empty.
285	pub fn jjrz_parse_reslate_input(markdown: &str) -> Result<Vec<(String, String)>, String> {
286	    let g = jjrz_Gazette::jjrz_parse(&[jjrz_Slug::Reslate], markdown)
287	        .map_err(|diags| diags.join("\n"))?;
